import {
  CurvePath,
  DoubleSide,
  Group,
  LineCurve3,
  Mesh,
  MeshBasicMaterial,
  PlaneGeometry,
  ShaderMaterial,
  SphereGeometry,
  sRGBEncoding,
  TextureLoader,
  TubeGeometry,
  Vector3,
} from 'three'

// 移动端纹理贴图（只有十字不带圆圈）
const mobileTextureUrl = `data:image/png;base64,`

// pc端纹理贴图（带圆圈）
const pcTextureUrl = `data:image/png;base64,`

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  vec4 mvPosition = modelViewMatrix * vec4(position, 1);
  gl_Position = projectionMatrix * mvPosition;
}
`
const fragmentShader = `
varying vec2 vUv;
void main() {
  vec2 uv = vec2(vUv.x, vUv.y);
  float a = 1.0;
  float match = 1.0 - uv.x;
  gl_FragColor = vec4(1.0,1.0,1.0,match);
}
`

export function getMouseGroup(isMobile = false) {
  const group = new Group()
  // 底部纹理贴图面片
  const planGeometry = new PlaneGeometry(0.3, 0.3)
  const planTextureUrl = isMobile ? mobileTextureUrl : pcTextureUrl
  const planTexture = new TextureLoader().load(planTextureUrl)
  planTexture.encoding = sRGBEncoding
  const planMaterial = new MeshBasicMaterial({
    map: planTexture,
    transparent: true,
    depthTest: false,
  })
  const planMesh = new Mesh(planGeometry, planMaterial)
  // 法向量垂直管
  const zPath = new CurvePath<Vector3>()
  zPath.add(new LineCurve3(new Vector3(0, 0, 0), new Vector3(0, 0, 0.1)))
  const zGeometry = new TubeGeometry(zPath, 8, 0.003)
  const zMaterial = new ShaderMaterial({
    vertexShader: vertexShader,
    fragmentShader: fragmentShader,
    depthTest: false,
    transparent: true,
  })
  const zMesh = new Mesh(zGeometry, zMaterial)
  // 法向量圆球
  const ballGeometry = new SphereGeometry(0.01, 20, 20)
  const ballMaterial = new MeshBasicMaterial({
    color: 0x9ded6b,
    depthTest: false,
    transparent: true,
    side: DoubleSide,
  })
  const ballMesh = new Mesh(ballGeometry, ballMaterial)
  ballMesh.position.set(0, 0, 0.1)

  group.name = 'mouse-current'
  group.add(planMesh, zMesh, ballMesh)
  return group
}
